hbs.a_button:
{{#if href}}<a
 href="{{href}}"{{else}}<span{{/if}}
 class="a_button {{style}}">
{{> a_icon icon=icon_before }}
<span>{{text}}</span>
{{> a_icon icon=icon_after }}
{{#if href}}</a>{{else}}</span>{{/if}}

hbs.a_icon:
{{#with a_icon}}
{{> a_icon }}
{{else}}
{{#if icon}}
<span class="a_icon"
 data-icon="{{icon}}"
 style="--icon: {{lucideSvgUrl icon fill stroke stroke_width}}"
 aria-hidden="true"></span>
{{/if}}
{{/with}}

hbs.a_image:
{{#if a_image.src}}
<{{#if a_image.href}}a href="{{a_image.href}}"{{else}}div{{/if}} class="a_image">
<img
 src="{{a_image.src}}"
 alt="{{a_image.alt}}"
 {{#if a_image.width}} width="{{parseInt a_image.width}}"{{/if}}
 {{#if a_image.height}} height="{{parseInt a_image.height}}"{{/if}}
 {{#if a_image.fetchpriority}} fetchpriority="{{a_image.fetchpriority}}"{{/if}}
 {{#if a_image.loading}} loading="{{a_image.loading}}"{{/if}}
 />
</{{#if a_image.href}}a{{else}}div{{/if}}>
{{/if}}

hbs.a_image_cover:
{{#if a_image_cover.src}}
<div class="a_image_cover">
<img
 src="{{a_image_cover.src}}"
 alt="{{a_image_cover.alt}}"
 {{#if a_image_cover.fetchpriority}} fetchpriority="{{a_image_cover.fetchpriority}}"{{/if}}
 {{#if a_image_cover.loading}} loading="{{a_image_cover.loading}}"{{/if}}
 />
</div>
{{/if}}

hbs.o_breadcrumbs:
{{#if items}}
<section class="o_breadcrumbs container"
{{#if section_id}}
 id="{{section_id}}"
{{/if}}>
<nav aria-label="Breadcrumb">
{{#each items}}
{{#if href}}
<a href="{{href}}">{{text}}</a>
{{else}}
<span class="active"
 aria-current="page">{{text}}</span>
{{/if}}
{{#unless @last}}
<span class="separator">/</span>
{{/unless}}
{{/each}}
</nav>
<script type="application/ld+json">
{
"@context": "https://schema.org",
"@type": "BreadcrumbList",
"itemListElement": [
{{#each items}}
{
"@type": "ListItem",
"position": {{inc @index}},
"name": {{json text}}{{#if href}},
"item": {{json href}}{{/if}}
 }{{#unless @last}},{{/unless}}
{{/each}}
]
}
</script>
</section>
{{/if}}

